package stepik.ContactsApp.config.security;

import io.jsonwebtoken.io.Decoders;
import io.jsonwebtoken.security.Keys;
import jakarta.servlet.http.HttpServletResponse;
import lombok.RequiredArgsConstructor;
import org.springframework.beans.factory.annotation.Value;
import org.springframework.context.annotation.Bean;
import org.springframework.context.annotation.Configuration;
import org.springframework.security.authentication.AuthenticationManager;
import org.springframework.security.authentication.AuthenticationProvider;
import org.springframework.security.authentication.dao.DaoAuthenticationProvider;
import org.springframework.security.config.Customizer;
import org.springframework.security.config.annotation.authentication.configuration.AuthenticationConfiguration;
import org.springframework.security.config.annotation.web.builders.HttpSecurity;
import org.springframework.security.config.annotation.web.configuration.EnableWebSecurity;
import org.springframework.security.config.annotation.web.configurers.AbstractHttpConfigurer;
import org.springframework.security.config.http.SessionCreationPolicy;
import org.springframework.security.crypto.bcrypt.BCryptPasswordEncoder;
import org.springframework.security.crypto.password.PasswordEncoder;
import org.springframework.security.oauth2.jwt.JwtDecoder;
import org.springframework.security.oauth2.jwt.NimbusJwtDecoder;
import org.springframework.security.oauth2.server.resource.authentication.JwtAuthenticationConverter;
import org.springframework.security.oauth2.server.resource.authentication.JwtGrantedAuthoritiesConverter;
import org.springframework.security.web.SecurityFilterChain;
import org.springframework.security.web.authentication.UsernamePasswordAuthenticationFilter;
import stepik.ContactsApp.model.enums.AppRole;
import stepik.ContactsApp.service.contacts.ContactOwnerService;

import javax.crypto.SecretKey;

@Configuration
@EnableWebSecurity
@RequiredArgsConstructor
public class SecurityConfig {

    private final stepik.ContactsApp.config.security.JwtAuthenticationFilter authenticationFilter;
    private final ContactOwnerService contactOwnerService;

    // секретный ключ для jwt токена
    @Value("${jwt.secret-key}")
    private String SECRET_KEY;

    @Bean
    // декодер для пароля
    public PasswordEncoder passwordEncoder() {
        return new BCryptPasswordEncoder();
    }

    @Bean
    // авторизация для jwt токена
    // логика для проверки пользователя и пароля, а также для генерации jwt токена
    public AuthenticationProvider authProvider() {
        // создаем провайдера для аутентификации и устанавливаем детали пользователя и кодировщик пароля
        DaoAuthenticationProvider authProvider = new DaoAuthenticationProvider();
        authProvider.setUserDetailsService(contactOwnerService.getUserDetailsService());
        authProvider.setPasswordEncoder(passwordEncoder());
        return authProvider;
    }

    @Bean
    // создание менеджера аутентификации
    public AuthenticationManager authenticationManager(
            AuthenticationConfiguration config) throws Exception {
        // проверка учётных данных и возврат аутентифицированного менеджера для входа в в систему
        return config.getAuthenticationManager();
    }

    @Bean
    // декодер для jwt токена
    public JwtDecoder jwtDecoder() {
        return NimbusJwtDecoder
                .withSecretKey(secretKey())
                .build();
    }

    // создание секретного ключа для jwt токена
    private SecretKey secretKey() {
        return Keys.hmacShaKeyFor(Decoders.BASE64.decode(SECRET_KEY));
    }

    @Bean
    // создание конвертера для извлечения прав доступа из jwt токена
    // будет использоваться роль пользователя в качестве привилегии
    public JwtAuthenticationConverter jwtAuthenticationConverter() {
        JwtGrantedAuthoritiesConverter authoritiesConverter = new JwtGrantedAuthoritiesConverter();
        authoritiesConverter.setAuthoritiesClaimName("role");
        // стандартный префикс для ролей, который будет добавлен к каждой роли в jwt токене
        // по умолчанию префикс - "ROLE_", а у нас роли просто "USER" или "ADMIN" без префикса
        authoritiesConverter.setAuthorityPrefix("");

        JwtAuthenticationConverter converter = new JwtAuthenticationConverter();
        converter.setJwtGrantedAuthoritiesConverter(authoritiesConverter);
        return converter;
    }

    @Bean
    // создание цепочки фильтров для безопасности
    public SecurityFilterChain securityFilterChain(HttpSecurity httpSecurity)
            throws Exception {
        httpSecurity
                .csrf(AbstractHttpConfigurer::disable) // отключаем csrf защиту
                .cors(Customizer.withDefaults()) // включаем cors защиту
                .oauth2ResourceServer(oauth2 -> oauth2
                        .jwt(Customizer.withDefaults())) // включаем защиту от oauth2 ресурсов
                .authorizeHttpRequests(req -> req
                        .requestMatchers(
                                "/api/auth/**",
                                "/swagger-ui/**",
                                "/v3/api-docs/**",
                                "/swagger-ui.html") // включаем доступ к api и документации для swagger
                        .permitAll() //
                        .requestMatchers("/api/contact/**").hasAuthority(AppRole.USER.name()) // доступ к api контактов для пользователей с ролью USER
                        .requestMatchers("/api/owner/**").hasAuthority(AppRole.ADMIN.name())  // доступ к api владельцев контактов для пользователей с ролью ADMIN
                        .anyRequest().authenticated()) // остальные запросы требуют аутентификации
                .sessionManagement(m -> m.sessionCreationPolicy(SessionCreationPolicy.STATELESS)) // отключаем управление сессиями
                .authenticationProvider(authProvider()) // добавляем провайдера для аутентификации
                .addFilterBefore(authenticationFilter, UsernamePasswordAuthenticationFilter.class) // добавляем кастомный фильтр аутентификации
                .exceptionHandling(ex -> ex
                        .authenticationEntryPoint((request, response, authException) -> response
                                .sendError(HttpServletResponse.SC_UNAUTHORIZED, "Unauthorized"))); // обработка исключений аутентификации

        return httpSecurity.build(); // возврат настроенной цепочки фильтров для безопасности
    }
}

package stepik.ContactsApp.config.security;

import io.micrometer.common.util.StringUtils;
import jakarta.servlet.FilterChain;
import jakarta.servlet.ServletException;
import jakarta.servlet.http.HttpServletRequest;
import jakarta.servlet.http.HttpServletResponse;
import lombok.RequiredArgsConstructor;
import org.springframework.security.authentication.UsernamePasswordAuthenticationToken;
import org.springframework.security.core.context.SecurityContext;
import org.springframework.security.core.context.SecurityContextHolder;
import org.springframework.security.core.userdetails.UserDetails;
import org.springframework.security.web.authentication.WebAuthenticationDetailsSource;
import org.springframework.stereotype.Component;
import org.springframework.web.filter.OncePerRequestFilter;
import stepik.ContactsApp.service.contacts.ContactOwnerService;
import stepik.ContactsApp.service.security.JwtSecurityService;

import java.io.IOException;

/**
* JwtAuthenticationFilter - это фильтр, который проверяет наличие токена JWT в заголовке Authorization
* запроса и аутентифицирует пользователя, если токен валиден.
* Если токен отсутствует, то запрос пропускается дальше без аутентификации.
* Если токен валиден, то создается новая сессия для аутентифицированного пользователя.
* Если токен не валиден, запрос пропускается дальше без аутентификации.
*/

@Component
@RequiredArgsConstructor
public class JwtAuthenticationFilter extends OncePerRequestFilter {

    private final JwtSecurityService jwtSecurityService;
    private final ContactOwnerService contactOwnerService;

    @Override
    protected void doFilterInternal(
            HttpServletRequest request,
            HttpServletResponse response,
            FilterChain filterChain) throws ServletException, IOException {

        String header = request.getHeader("Authorization");

        // если токен отсутствует или не начинается с Bearer, пропускаем запрос
        if (header.isEmpty() || !header.substring(0, 7).equals("Bearer ")) {
            filterChain.doFilter(request, response);
            return; // вылет без аутентификации
        }

        // получение токена из заголовка запроса
        String jwt = header.substring(7); // убираем "Bearer " из заголовка
        String email = jwtSecurityService.extractUsername(jwt);

        // если email есть в токене и аутентификации нет, то создаем новую сессию
        if (StringUtils.isNotEmpty(email)
                && SecurityContextHolder.getContext().getAuthentication() == null) {
            UserDetails userDetails = contactOwnerService
                    .getUserDetailsService()
                    .loadUserByUsername(email);

            // если токен валиден, то устанавливаем аутентификацию
            if (jwtSecurityService.validateToken(jwt, userDetails)) {
                // создание пустого контекста безопасности
                SecurityContext securityContext = SecurityContextHolder.createEmptyContext();

                // создание токена аутентификации и установка его в контекст безопасности
                UsernamePasswordAuthenticationToken token = new UsernamePasswordAuthenticationToken(
                        userDetails, null, userDetails.getAuthorities());
                // установка дополнительных деталей о запросе в токен аутентификации
                token.setDetails(new WebAuthenticationDetailsSource().buildDetails(request));
                securityContext.setAuthentication(token);
                SecurityContextHolder.setContext(securityContext);
            }
        }
        // пропуск запроса дальше в цепочку фильтров
        filterChain.doFilter(request, response);
    }
}

package stepik.ContactsApp.service.contacts;

import org.modelmapper.ModelMapper;
import org.springframework.beans.factory.annotation.Autowired;
import org.springframework.security.core.authority.SimpleGrantedAuthority;
import org.springframework.security.core.userdetails.User;
import org.springframework.security.core.userdetails.UserDetails;
import org.springframework.security.core.userdetails.UserDetailsService;
import org.springframework.security.core.userdetails.UsernameNotFoundException;
import org.springframework.stereotype.Service;
import org.springframework.transaction.annotation.Transactional;
import stepik.ContactsApp.dao.JpaContactOwnerRepositoryAdapter;
import stepik.ContactsApp.exception.handler.customException.EntityNotFoundException;
import stepik.ContactsApp.exception.handler.customException.ValidationException;
import stepik.ContactsApp.model.dto.ContactOwnerDTO;
import stepik.ContactsApp.model.dto.CreateContactOwnerDTO;
import stepik.ContactsApp.model.dto.UpdateContactOwnerDTO;
import stepik.ContactsApp.model.entity.ContactOwner;

import java.util.ArrayList;
import java.util.Collections;
import java.util.List;
import java.util.stream.Collectors;

@Service
@Transactional
public class ContactOwnerService implements ContactOwnerServiceInterface {
    private final ModelMapper modelMapper;
    private final JpaContactOwnerRepositoryAdapter contactOwnerRepository;

    @Autowired
    public ContactOwnerService(JpaContactOwnerRepositoryAdapter contactOwnerRepository, ModelMapper modelMapper) {
        this.contactOwnerRepository = contactOwnerRepository;
        this.modelMapper = modelMapper;
    }

    @Override
    public List<ContactOwnerDTO> getContactOwnersAll() {
        return contactOwnerRepository.findAll().stream()
                .map(owner -> modelMapper.map(owner, ContactOwnerDTO.class))
                .collect(Collectors.toList());
//        return contactOwnerRepository.findAll();
    }

    @Override
    public ContactOwner getContactOwner(String id) {
        return contactOwnerRepository.findById(id)
                .orElseThrow(() -> new EntityNotFoundException("Владелец контактов " + id + "  не найден"));
    }

    @Override
    public ContactOwner createContactOwner(CreateContactOwnerDTO dto) {
        contactOwnerRepository.findByEmail(dto.getEmail())
                .ifPresent(owner -> {
                    throw new ValidationException("Владелец контактов с eMail '" + dto.getEmail() + "' уже существует");
                });

        contactOwnerRepository.findByUsername(dto.getUsername())
                .ifPresent(owner -> {
                    throw new ValidationException("Владелец контактов с логином '" + dto.getUsername() + "' уже существует");
                });

        ContactOwner owner = modelMapper.map(dto, ContactOwner.class);
        return contactOwnerRepository.save(owner);
    }

    @Override
    public ContactOwner updateContactOwner(UpdateContactOwnerDTO dto) {
        ContactOwner ownerInRepository = contactOwnerRepository.findById(dto.getId())
                .orElseThrow(() -> new EntityNotFoundException("Владелец контактов " + dto.getId() + " не найден"));

        contactOwnerRepository.findByEmail(dto.getEmail())
                .ifPresent(owner -> {
                    if (owner.getId().equals(dto.getId())) {
                        throw new ValidationException("Владелец контактов с eMail '" + dto.getEmail() + "' уже существует");
                    }
                });

        modelMapper.map(dto, ownerInRepository); // мапируются только где not null
        return contactOwnerRepository.save(ownerInRepository);
    }

    @Override
    public boolean deleteContactOwner(String id) {
        if (contactOwnerRepository.findById(id).isEmpty()) {
            throw new EntityNotFoundException("Владелец контактов " + id + " не найден");
        }
        return contactOwnerRepository.deleteById(id);
    }

    public ContactOwner getContactOwnerByUsername(String username) {
        return contactOwnerRepository.findByUsername(username)
                .orElseThrow(() -> new EntityNotFoundException("Владелец контактов '" + username + "'  не найден"));
    }

    public ContactOwner getContactOwnerByEmail(String email) {
        return contactOwnerRepository.findByEmail(email)
                .orElseThrow(() -> new EntityNotFoundException("Владелец контактов с почтой '" + email + "'  не найден"));
    }

    public List<ContactOwner> getContactOwnersByKeyword(String keyword) {
        return contactOwnerRepository.findByKeyword(keyword)
                .orElseThrow(() -> new EntityNotFoundException("Владельцев контактов по слову'" + keyword + "'  не найдено"));
    }

    // метод для получения UserDetailsService для аутентификации
    @Override
    public UserDetailsService getUserDetailsService() {
        return new UserDetailsService() {
            @Override
            public UserDetails loadUserByUsername(String username)
                    throws UsernameNotFoundException {

                ContactOwner user = contactOwnerRepository
                        .findByEmail(username)
                        .orElseThrow(() -> new UsernameNotFoundException("Такого пользователя не существует"));

                return new User(
                        user.getEmail(), // вместо username у нас используется email
                        user.getPassword(),
                        Collections.singletonList(new SimpleGrantedAuthority(user.getRole().name()))
                );
            }
        };
    }
}

package stepik.ContactsApp.service.security;

import lombok.RequiredArgsConstructor;
import org.springframework.security.authentication.AuthenticationManager;
import org.springframework.security.authentication.UsernamePasswordAuthenticationToken;
import org.springframework.security.core.Authentication;
import org.springframework.security.core.userdetails.UsernameNotFoundException;
import org.springframework.security.crypto.password.PasswordEncoder;
import org.springframework.stereotype.Service;
import stepik.ContactsApp.dao.JpaContactOwnerRepositoryAdapter;
import stepik.ContactsApp.model.entity.ContactOwner;
import stepik.ContactsApp.model.enums.AppRole;
import stepik.ContactsApp.model.dto.LoginRequestDTO;
import stepik.ContactsApp.model.dto.LoginResponseDTO;
import stepik.ContactsApp.model.dto.RegisterRequestDTO;
import stepik.ContactsApp.model.dto.RefreshTokenRequestDTO;
import stepik.ContactsApp.model.dto.RefreshTokenResponseDTO;

import java.util.HashMap;

@Service
@RequiredArgsConstructor
public class AuthenticationService {
    private final JpaContactOwnerRepositoryAdapter contactOwnerRepository;
    private final PasswordEncoder passwordEncoder;

    private final JwtSecurityService jwtSecurityService;
    private final AuthenticationManager authenticationManager;

    // Метод для регистрации и сохранения нового пользователя
    public ContactOwner register(RegisterRequestDTO registerRequestDTO) {
        // Создание нового пользователя с хешированным паролем и ролью USER
        ContactOwner appUser = new ContactOwner();
        appUser.setUsername(registerRequestDTO.getUsername());
        appUser.setEmail(registerRequestDTO.getEmail());
        appUser.setPassword(passwordEncoder.encode(registerRequestDTO.getPassword()));
        appUser.setRole(AppRole.USER);

        return contactOwnerRepository.save(appUser);
    }

    // Метод логирования и генерации токена и refresh tokenа
    public LoginResponseDTO login(LoginRequestDTO loginRequestDTO) {

        // Аутентификация пользователя и генерация токена и refresh tokenа
        Authentication authentication = authenticationManager.authenticate(
                new UsernamePasswordAuthenticationToken(
                        loginRequestDTO.getEmail(),
                        loginRequestDTO.getPassword()));

        // Получение данных пользователя из репозитория
        ContactOwner user = contactOwnerRepository
                .findByEmail(loginRequestDTO.getEmail())
                .orElseThrow(() -> new UsernameNotFoundException("Ошибка"));

        //
        String token = jwtSecurityService.generateToken(user);
        String refreshToken = jwtSecurityService
                .generateRefreshToken(new HashMap<>(), user);

        // Возврат токена и refresh tokena
        return LoginResponseDTO
                .builder()
                .email(loginRequestDTO.getEmail())
                .jwtToken(token)
                .refreshToken(refreshToken)
                .build();
    }

    //
    public RefreshTokenResponseDTO refresh(RefreshTokenRequestDTO refreshTokenRequestDTO) {
        String jwt = refreshTokenRequestDTO.getRefreshToken();
        String email = jwtSecurityService.extractUsername(jwt); // Извлечение email=username из токена
        ContactOwner user = contactOwnerRepository // Поиск пользователя по email в репозитории
                .findByEmail(email)
                .orElseThrow();

        if (jwtSecurityService.validateToken(jwt, user)) {
            // Проверка токена и генерация новых токенов
            RefreshTokenResponseDTO refreshTokenResponseDTO = new RefreshTokenResponseDTO();
            // Генерация новых токенов
            refreshTokenResponseDTO
                    .setJwtToken(jwtSecurityService.generateToken(user));
            // Генерация нового refresh tokena
            refreshTokenResponseDTO
                    .setRefreshToken(jwtSecurityService.generateRefreshToken(new HashMap<>(), user));
            // Возврат новых токенов
            return refreshTokenResponseDTO;
        }

        return null;
    }
}

package stepik.ContactsApp.service.security;

import io.jsonwebtoken.Claims;
import io.jsonwebtoken.Jwts;
import io.jsonwebtoken.io.Decoders;
import io.jsonwebtoken.security.Keys;
import org.springframework.beans.factory.annotation.Value;
import org.springframework.security.core.GrantedAuthority;
import org.springframework.security.core.userdetails.UserDetails;
import org.springframework.stereotype.Service;
import stepik.ContactsApp.model.entity.ContactOwner;

import javax.crypto.SecretKey;
import java.util.Date;
import java.util.Map;
import java.util.function.Function;

@Service
public class JwtSecurityService {

    // секретный ключ для подписи JWT токенов (см. конфигурацию в application.properties)
    @Value("${jwt.secret-key}")
    private String SECRET_KEY;

    // метод для получения (расшифровки) секретного ключа (см. конфигурацию в application.properties)
    private SecretKey getSigningKey() {
        byte[] keyBytes = Decoders.BASE64.decode(SECRET_KEY);
        return Keys.hmacShaKeyFor(keyBytes);
    }

    // метод для генерации токенов
    public String generateToken(UserDetails userDetails) {
        ContactOwner co = (ContactOwner) userDetails;
        return Jwts.builder()
                .subject(co.getEmail())
                .claim("contactOwnerId", co.getId())
                .claim("role", co.getAuthorities().stream()
                        .findFirst()
                        .map(GrantedAuthority::getAuthority)
                        .orElse("USER"))
                .issuedAt(new Date(System.currentTimeMillis()))
                .expiration(new Date(System.currentTimeMillis() + 1000 * 60 * 15)) // это 15 минут!
                .signWith(getSigningKey())
                .compact();
    }

    // метод для генерации refresh-токенов (реакция на бездействие в программе)
    public String generateRefreshToken(Map<String, String> claims, UserDetails userDetails) {
        ContactOwner co = (ContactOwner) userDetails;
        return Jwts.builder()
                .claims(claims)
                .subject(co.getEmail())
                .issuedAt(new Date(System.currentTimeMillis()))
                .expiration(new Date(System.currentTimeMillis() + 1000 * 60 * 60 * 24 * 7)) // 7 дней!
                .signWith(getSigningKey())
                .compact();
    }

    // метод для извлечения конкретного claim (данных) из JWT токена
    // на входе - токен и функция, которая будет использоваться для извлечения claim,
    // на выходе - значение claim
    private <T> T extractClaim(String token, Function<Claims, T> claimsResolver) {
        final Claims claims = extractAllClaims(token);
        return claimsResolver.apply(claims);
    }

    // метод для извлечения всех claims (данных) из JWT токена
    // на входе - токен, на выходе - claims (данные)
    private Claims extractAllClaims(String token) {
        return Jwts.parser()
                .verifyWith(getSigningKey())
                .build()
                .parseSignedClaims(token)
                .getPayload();
    }

    // методы для извлечения конкретных claims (данных) из JWT токена
    public String extractUsername(String token) {
        return extractClaim(token, Claims::getSubject); // у нас в subject хранится email пользователя
        // мы решили для аутентификации использовать email, а не username
    }

    // метод для получения времени истечения токена (для проверки валидности)
    public Date extractExpiration(String token) {
        return extractClaim(token, Claims::getExpiration);
    }

    // метод для получения времени создания токена (для проверки валидности)
    public Date extractIssuedAt(String token) {
        return extractClaim(token, Claims::getIssuedAt);
    }

    // метод для проверки валидности токена по времени истечения
    public boolean isTokenExpired(String token) {
        return extractExpiration(token).before(new Date());
    }

    // метод для проверки валидности токена
    // проверяем, что пользователь, выдавший запрос, имеет именно ту почту, которая хранится в токене
    public boolean validateToken(String token, UserDetails userDetails) {
        final String username = extractUsername(token);
        return (username.equals(userDetails.getUsername())
                && !isTokenExpired(token));
    }
}

package stepik.ContactsApp.model.enums;

public enum AppRole {
    USER, ADMIN
}

package stepik.ContactsApp.model.entity;

import com.fasterxml.jackson.annotation.JsonManagedReference;
import com.fasterxml.jackson.annotation.JsonProperty;
import jakarta.persistence.*;
import org.springframework.security.core.GrantedAuthority;
import org.springframework.security.core.authority.SimpleGrantedAuthority;
import org.springframework.security.core.userdetails.UserDetails;
import stepik.ContactsApp.common.utils.authentification.UserAuthentification;
import stepik.ContactsApp.model.enums.AppRole;
import com.fasterxml.jackson.annotation.JsonIgnore;
import lombok.Getter;
import lombok.Setter;

import java.util.*;

@Entity
@Table(name = "contact_owners")
@Getter
@Setter
public class ContactOwner implements UserDetails // интерфейс UserDetails используется для аутентификации
{
    @Id
    @JsonProperty(index = 10)
    private String id;
    @JsonProperty(index = 20)
    private String username;
    @JsonIgnore
    private String password;
    @JsonProperty(index = 30)
    private String description;
    @JsonProperty(index = 40)
    private String email;
    @Column(name = "name")
    @JsonProperty(index = 50)
    private String fullName;
    @Enumerated(EnumType.STRING)
    @JsonProperty(index = 60)
    private AppRole role;

    @OneToMany(
            mappedBy = "owner",
            cascade = CascadeType.ALL,
            orphanRemoval = true,
            fetch = FetchType.EAGER
    )
    @JsonManagedReference  // ← основная сторона (сериализуется)
    @JsonProperty(index = 999)
    private List<Contact> contacts = new ArrayList<>();

    public ContactOwner() {
        this.id = UserAuthentification.getNewUserId();
        this.role = UserAuthentification.getNewUserRole();
        this.contacts = new ArrayList<>();
    }

    public ContactOwner(String username, String description) {
        this();
        this.username = username;
        this.description = description;
        this.role = UserAuthentification.getNewUserRole(username);
    }

    public ContactOwner(
            String id,
            String username,
            String password,
            String description,
            String email,
            String fullName,
            AppRole role
    ) {
        this();
        if (id != null && !id.isEmpty()) {
            this.id = id;
        }
        this.username = username;
        this.password = password;
        this.description = description;
        this.email = email;
        this.fullName = fullName;
        if (role != null && !role.name().isEmpty()) {
            this.role = role;
        }
    }

    @Override
    public boolean equals(Object obj) {
        if (this == obj) return true;
        if (obj == null || !(obj instanceof ContactOwner)) return false;
        ContactOwner that = (ContactOwner) obj;
        if (Objects.equals(this.id, that.id)
                && (that.username.equalsIgnoreCase(this.username))
                && (that.email.equalsIgnoreCase(this.email))) return true;
        return false;
    }

    @Override
    public int hashCode() {
        return Objects.hash(id, username.toLowerCase(), email.toLowerCase());

